<template>
    <div id="status">
        <loadings :isLoading="settings.base.beforeLoad? 1: 0"></loadings>
        <div v-if="!settings.base.beforeLoad" >
            <NavBar :isActive="settings.base.belong" :isLogin="settings.base.isLogin" :user="settings.base.userInfo"></NavBar>
            <div class="container mundb-standard-container" style="min-height: 70vh">
                <paper-card style="min-height: 350px">
                    <div>
                        <div class="no-scrollbar table-responsive">
                            <table id="result-tab" class="table">
                                <thead>
                                <tr>
                                    <th scope="col">
                                        RunID
                                    </th>
                                    <th scope="col">
                                        <!--<form class="form-inline"-->
                                        <!--style="margin-bottom: 0px" @submit.prevent="">-->
                                        <input v-model="settings.status.search.userInfo" class="form-control search-query"
                                               type="text" style="text-align: center"
                                               name="ufo" placeholder="User" @keydown.enter="chooseUserInfo">
                                        <!--</form>-->
                                    </th>
                                    <th scope="col">
                                        <input v-model="settings.status.search.problemId" class="form-control search-query"
                                               type="text" style="text-align: center"
                                               name="pid" placeholder="ID" @keydown.enter="chooseProblemId">
                                    </th>
                                    <th scope="col">
                                        <input v-model="settings.status.search.result"
                                               v-bind:class="['form-control', 'search-query', transResultColor(forms.statusForm.result)]"
                                               type="text" style="text-align: center;background-color: white;"
                                               name="res" placeholder="Result" readonly="readonly"
                                               id="dropdownMenuResult" @focus="switchResultType(1, true)"
                                               @blur="switchResultType(1, false)"/>
                                        <div class="pannel result-pannel" @mouseover="switchResultType(0, true)"
                                             @mouseleave="switchResultType(0, false)"
                                             v-bind:style="{width: '148.8px', display: settings.status.resultTypeList.a || settings.status.resultTypeList.b? '': 'none'}">
                                            <div class="dropdown-divider"></div>
                                            <div class="pannel-item wemd-grey-text"
                                                 @click="switchResult(null)">All
                                            </div>
                                            <div class="dropdown-divider"></div>
                                            <div class="pannel-item wemd-green-text"
                                                 @click="switchResult(GLOBAL.OJ_RESULT_ACCEPTED)">Accepted
                                            </div>
                                            <div class="dropdown-divider"></div>
                                            <div class="pannel-item wemd-blue-text"
                                                 @click="switchResult(GLOBAL.OJ_RESULT_COMPILING)">Compiling
                                            </div>
                                            <div class="dropdown-divider"></div>
                                            <div class="pannel-item wemd-orange-text"
                                                 @click="switchResult(GLOBAL.OJ_RESULT_COMPILATION_ERROR)">Compile Error
                                            </div>
                                            <div class="dropdown-divider"></div>
                                            <div class="pannel-item wemd-red-text"
                                                 @click="switchResult(GLOBAL.OJ_RESULT_WRONG_ANSWER)">Wrong Answer
                                            </div>
                                            <div class="dropdown-divider"></div>
                                            <div class="pannel-item wemd-red-text"
                                                 @click="switchResult(GLOBAL.OJ_RESULT_PRESENTATION_ERROR)">Presentation
                                                Error
                                            </div>
                                            <div class="dropdown-divider"></div>
                                            <div class="pannel-item wemd-red-text"
                                                 @click="switchResult(GLOBAL.OJ_RESULT_RUNTIME_ERROR)">Runtime Error
                                            </div>
                                            <div class="dropdown-divider"></div>
                                            <div class="pannel-item wemd-deep-purple-text"
                                                 @click="switchResult(GLOBAL.OJ_RESULT_TIME_LIMIT_EXCEEDED)">Time Limit
                                                Exceed
                                            </div>
                                            <div class="dropdown-divider"></div>
                                            <div class="pannel-item wemd-deep-purple-text"
                                                 @click="switchResult(GLOBAL.OJ_RESULT_MEMORY_LIMIT_EXCEEDED)">Memory Limit
                                                Exceed
                                            </div>
                                            <div class="dropdown-divider"></div>
                                            <div class="pannel-item wemd-deep-purple-text"
                                                 @click="switchResult(GLOBAL.OJ_RESULT_OUTPUT_LIMIT_EXCEEDED)">Output Limit
                                                Exceed
                                            </div>
                                            <div class="dropdown-divider"></div>
                                        </div>
                                    </th>
                                    <th scope="col">
                                        <div>
                                            <input style="width: 100%;background-color:white;text-align: center" v-model="settings.status.search.lang"
                                                   placeholder="Lang" class="form-control " type="text"
                                                   name="language" readonly="readonly"
                                                   @focus="switchLangType(1, true)"
                                                   @blur="switchLangType(1, false)">
                                            <div class="pannel lang-pannel" @mouseover="switchLangType(0, true)"
                                                 @mouseleave="switchLangType(0, false)"
                                                 v-bind:style="{width: '148.8px', display: settings.status.langTypeList.a || settings.status.langTypeList.b? '': 'none'}">
                                                <div class="dropdown-divider"></div>
                                                <div class="pannel-item"
                                                     @click="switchLang(null)">All
                                                </div>
                                                <div class="dropdown-divider"></div>
                                                <div class="pannel-item"
                                                     @click="switchLang(GLOBAL.OJ_LANG_C)">C
                                                </div>
                                                <div class="dropdown-divider"></div>
                                                <div class="pannel-item"
                                                     @click="switchLang(GLOBAL.OJ_LANG_CPLUS)">C++
                                                </div>
                                                <div class="dropdown-divider"></div>
                                                <div class="pannel-item"
                                                     @click="switchLang(GLOBAL.OJ_LANG_PASCAL)">Pascal
                                                </div>
                                                <div class="dropdown-divider"></div>
                                                <div class="pannel-item"
                                                     @click="switchLang(GLOBAL.OJ_LANG_JAVA)">Java
                                                </div>
                                                <div class="dropdown-divider"></div>
                                                <div class="pannel-item"
                                                     @click="switchLang(GLOBAL.OJ_LANG_RUBY)">
                                                    Ruby
                                                </div>
                                                <div class="dropdown-divider"></div>
                                                <div class="pannel-item"
                                                     @click="switchLang(GLOBAL.OJ_LANG_BASH)">Bash
                                                </div>
                                                <div class="dropdown-divider"></div>
                                                <div class="pannel-item"
                                                     @click="switchLang(GLOBAL.OJ_LANG_PYTHON)">Python
                                                </div>
                                                <div class="dropdown-divider"></div>
                                                <div class="pannel-item"
                                                     @click="switchLang(GLOBAL.OJ_LANG_PHP)">PHP
                                                </div>
                                                <div class="dropdown-divider"></div>
                                                <div class="pannel-item"
                                                     @click="switchLang(GLOBAL.OJ_LANG_PERL)">Perl
                                                </div>
                                                <div class="dropdown-divider"></div>
                                            </div>
                                        </div>
                                    </th>
                                    <th scope="col">
                                        Memory
                                    </th>
                                    <th scope="col">
                                        Time
                                    </th>
                                    <th scope="col">
                                        Code Length
                                    </th>
                                    <th scope="col">
                                        Submit Time
                                    </th>
                                </tr>
                                </thead>
                                <tbody>
                                <tr v-for="saved_solution in result.statusForm.solution" v-bind:key="key">
                                    <td>{{saved_solution.solutionId}}</td>
                                    <td>{{saved_solution.nick}}</td>
                                    <td><a style="text-decoration: none"
                                           v-bind:href="'/problem.html?pid=' + saved_solution.problemId">CAOJ{{saved_solution.problemId}}</a>
                                    </td>
                                    <td v-bind:class="[transResultColor(saved_solution.result)]">
                                        {{transResultString(saved_solution.result)}}
                                    </td>
                                    <td>{{transLangString(saved_solution.language)}}</td>
                                    <td>{{saved_solution.memory == -1? "---": saved_solution.memory/1024+' KB'}}</td>
                                    <td>{{saved_solution.time == -1? "---": saved_solution.time+' ms'}}</td>
                                    <td>{{saved_solution.codeLength}}</td>
                                    <td>{{diffTime(saved_solution.createTime)}}</td>
                                </tr>
                                </tbody>
                            </table>
                            <empty-container v-if="result.statusForm.solution != null && result.statusForm.solution.length <= 0">
                                <svg t="1605936727818" class="icon" viewBox="0 0 1024 1024" version="1.1"
                                     xmlns="http://www.w3.org/2000/svg" p-id="3621" width="100" height="100">
                                    <path d="M576 928c-6 0-11.9-1.7-17.1-5-9.3-5.9-14.9-16.1-14.9-27V554.3c0-12.4 7.1-23.6 18.3-28.9l288-136.1c9.9-4.7 21.5-4 30.8 1.9s14.9 16.1 14.9 27v341.7c0 12.4-7.1 23.6-18.3 28.9l-288 136.1c-4.4 2.1-9 3.1-13.7 3.1z m32-353.5v271l224-105.8v-271L608 574.5zM448 928c-4.7 0-9.3-1-13.7-3.1l-288-136.1c-11.2-5.3-18.3-16.6-18.3-28.9V418.2c0-11 5.6-21.2 14.9-27 9.3-5.9 20.9-6.6 30.8-1.9l288 136.1c11.2 5.3 18.3 16.6 18.3 28.9V896c0 11-5.6 21.2-14.9 27-5.2 3.3-11.1 5-17.1 5zM192 739.7l224 105.8v-271L192 468.7v271zM512 501.1c-4.7 0-9.4-1-13.8-3.1l-352-168.1c-11.2-5.4-18.3-16.7-18.2-29.2 0.1-12.4 7.4-23.7 18.8-28.8l352-159.9c8.4-3.8 18.1-3.8 26.5 0l352 159.9c11.3 5.1 18.6 16.4 18.8 28.8 0.1 12.4-7 23.8-18.2 29.2L525.8 498c-4.4 2-9.1 3.1-13.8 3.1zM235.8 301.7L512 433.6l276.2-131.9L512 176.2 235.8 301.7z"
                                          p-id="3622" fill="#7a8e97"></path>
                                </svg>
                                <p>Nothing matches.</p>
                            </empty-container>
                        </div>
                    </div>
                </paper-card>
                <nav aria-label="..." class="animated bounceInLeft" style="min-height: 36px">
                    <ul class="pagination justify-content-center">
                        <li v-bind:class="{'page-item':true, 'disable': settings.status.page <= 1}">
                            <a class="page-link cm-navi" @click="switchPage(settings.status.page-1)" href="javascript:void(0)">
                                <i style="line-height: 18px;" v-bind:style="{'color': settings.status.page <= 1? 'grey': ''}"
                                   class="material-icons prefix">chevron_left</i>
                            </a>
                        </li>
                        <template v-if="settings.status.maxPage <= 14">
                            <li v-bind:class="{'page-item': true, 'active': i == settings.status.page}"
                                v-for="i in pageIndexRange(1, settings.status.maxPage)" v-bind:key="key">
                                <a v-if="settings.status.page != i" class="page-link" href="javascript:(0)" @click="switchPage(i)">{{i}}</a>
                                <span v-else class="page-link">{{settings.status.page}}</span>
                            </li>
                        </template>
                        <template v-else>
                            <template v-if="settings.status.page < 7">
                                <li v-bind:class="{'page-item': true, 'active': i == settings.status.page}"
                                    v-for="i in pageIndexRange(1, settings.status.page+3)" v-bind:key="key">
                                    <a v-if="settings.status.page != i" class="page-link" href="javascript:(0)"
                                       @click="switchPage(i)">{{i}}</a>
                                    <span v-else class="page-link">{{settings.status.page}}</span>
                                </li>
                                <li class="page-item disabled" aria-disabled="true"><span
                                        class="page-link">...</span>
                                </li>
                                <li class="page-item" v-for="i in pageIndexRange(settings.status.maxPage-2, settings.status.maxPage)"
                                    v-bind:key="key">
                                    <a class="page-link" href="javascript:(0)" @click="switchPage(i)">{{i}}</a>
                                </li>
                            </template>
                            <template v-else-if="settings.status.page >= settings.status.maxPage - 5">
                                <li class="page-item" v-for="i in 3" v-bind:key="key">
                                    <a class="page-link" href="javascript:(0)" @click="switchPage(i)">{{i}}</a>
                                </li>
                                <li class="page-item disabled" aria-disabled="true"><span
                                        class="page-link">...</span>
                                </li>
                                <li v-bind:class="{'page-item': true, 'active': i == settings.status.page}"
                                    v-for="i in pageIndexRange(settings.status.page-3, settings.status.maxPage)"
                                    v-bind:key="key">
                                    <a v-if="page != i" class="page-link" href="javascript:(0)"
                                       @click="switchPage(i)">{{i}}</a>
                                    <span v-else class="page-link">{{settings.status.page}}</span>
                                </li>
                            </template>
                            <template v-else>
                                <li class="page-item" v-for="i in 3" v-bind:key="key">
                                    <a class="page-link" href="javascript:(0)" @click="switchPage(i)">{{i}}</a>
                                </li>
                                <li class="page-item disabled" aria-disabled="true"><span
                                        class="page-link">...</span>
                                </li>
                                <li v-bind:class="{'page-item': true, 'active': i == settings.status.page}"
                                    v-for="i in pageIndexRange(settings.status.page-3, settings.status.page+3)"
                                    v-bind:key="key">
                                    <a v-if="settings.status.page != i" class="page-link" href="javascript:(0)"
                                       @click="switchPage(i)">{{i}}</a>
                                    <span v-else class="page-link">{{settings.status.page}}</span>
                                </li>
                                <li class="page-item disabled" aria-disabled="true"><span
                                        class="page-link">...</span>
                                </li>
                                <li class="page-item" v-for="i in pageIndexRange(settings.status.maxPage-2, settings.status.maxPage)"
                                    v-bind:key="key">
                                    <a class="page-link" href="javascript:(0)" @click="switchPage(i)">{{i}}</a>
                                </li>
                            </template>
                        </template>
                        <li v-bind:class="{'page-item':true, 'disable': settings.status.page >= settings.status.maxPage}">
                            <a class="page-link cm-navi" href="javascript:(0)" @click="switchPage(settings.status.page+1)">
                                <i style="line-height: 18px;" v-bind:style="{'color': settings.status.page >= settings.status.maxPage? 'grey': ''}"
                                   class="material-icons prefix">chevron_right</i>
                            </a>
                        </li>
                    </ul>
                </nav>
            </div>
            <footers></footers>
        </div>

    </div>

</template>

<script>
    /* eslint no-useless-escape: "off"*/
    /* eslint vue/valid-v-for: "off"*/
    import NavBar from "@/components/navbar/navbar";
    import Footers from "@/components/footer/footer";
    import Loadings from "../../components/loading/loading";
    import fun from '@/assets/js/OJFunction'
    // import {hex_md5} from "@/assets/js/include"
    // import VueResource from 'vue-resource'
    // import Vue from 'vue'
    export default {
        name: "status",
        components: {
            NavBar,
            Loadings,
            Footers
        },
        data() {
            return {

                settings: {
                    base:{
                        belong: 'status',
                        beforeLoad: true,
                        isLogin: false,
                        user: new Object(),
                    },
                    status:{
                        page: 0,
                        maxPage: 0,
                        search: {
                            userInfo: null,
                            problemId: null,
                            result: null,
                            lang: null
                        },
                        resultTypeList: {
                            a: false,
                            b: false
                        },
                        langTypeList: {
                            a: false,
                            b: false
                        },
                    },
                },
                forms:{
                    statusForm:{
                        page: null,
                        result: null,
                        userInfo: null,
                        problemId: null,
                        lang: null
                    }
                },
                result:{
                    statusForm:{
                        solution: [],
                    }
                },


            }
        },
        methods: {
            pageIndexRange: function (a, b) {
                var res = [];
                for (var i = a; i <= b; i++) {
                    res.push(i);
                }
                return res;
            },
            switchPage: function (p) {
                if (p >= 1 && p <= this.settings.status.maxPage) {
                    this.addUrlParm("page", p);
                    var url = "/status.html" + this.getUrlString();
                    window.location.href = url;
                }
            },
            diffTime: function (time) {
                time = fun.diffTime(time);
                if (time.year >= 1) {
                    if (time.year == 1) return time.year + this.$t('WARN.OJ_MESSAGE_TIME_AGO.OJ_YEAR.ONE') + this.$t('WARN.OJ_MESSAGE_TIME_AGO.OJ_AGO');
                    else return time.year + this.$t('WARN.OJ_MESSAGE_TIME_AGO.OJ_YEAR.MORE') + this.$t('WARN.OJ_MESSAGE_TIME_AGO.OJ_AGO');
                } else if (time.month >= 1) {
                    if (time.month == 1) return time.month + this.$t('WARN.OJ_MESSAGE_TIME_AGO.OJ_MONTH.ONE') + this.$t('WARN.OJ_MESSAGE_TIME_AGO.OJ_AGO');
                    else return time.month + this.$t('WARN.OJ_MESSAGE_TIME_AGO.OJ_MONTH.MORE') + this.$t('WARN.OJ_MESSAGE_TIME_AGO.OJ_AGO');
                } else if (time.week >= 1) {
                    if (time.week == 1) return time.week + this.$t('WARN.OJ_MESSAGE_TIME_AGO.OJ_WEEK.ONE') + this.$t('WARN.OJ_MESSAGE_TIME_AGO.OJ_AGO');
                    else return time.week + this.$t('WARN.OJ_MESSAGE_TIME_AGO.OJ_WEEK.MORE') + this.$t('WARN.OJ_MESSAGE_TIME_AGO.OJ_AGO');
                } else if (time.day >= 1) {
                    if (time.day == 1) return time.day + this.$t('WARN.OJ_MESSAGE_TIME_AGO.OJ_DAY.ONE') + this.$t('WARN.OJ_MESSAGE_TIME_AGO.OJ_AGO');
                    else return time.day + this.$t('WARN.OJ_MESSAGE_TIME_AGO.OJ_DAY.MORE') + this.$t('WARN.OJ_MESSAGE_TIME_AGO.OJ_AGO');
                } else if (time.hour >= 1) {
                    if (time.hour == 1) return time.hour + this.$t('WARN.OJ_MESSAGE_TIME_AGO.OJ_HOUR.ONE') + this.$t('WARN.OJ_MESSAGE_TIME_AGO.OJ_AGO');
                    else return time.hour + this.$t('WARN.OJ_MESSAGE_TIME_AGO.OJ_HOUR.MORE') + this.$t('WARN.OJ_MESSAGE_TIME_AGO.OJ_AGO');
                } else if (time.minute >= 1) {
                    if (time.minute == 1) return time.minute + this.$t('WARN.OJ_MESSAGE_TIME_AGO.OJ_MINUTE.ONE') + this.$t('WARN.OJ_MESSAGE_TIME_AGO.OJ_AGO');
                    else return time.minute + this.$t('WARN.OJ_MESSAGE_TIME_AGO.OJ_MINUTE.MORE') + this.$t('WARN.OJ_MESSAGE_TIME_AGO.OJ_AGO');
                } else {
                    if (time.second <= 1) return time.second + this.$t('WARN.OJ_MESSAGE_TIME_AGO.OJ_SECOND.ONE') + this.$t('WARN.OJ_MESSAGE_TIME_AGO.OJ_AGO');
                    else return time.second + this.$t('WARN.OJ_MESSAGE_TIME_AGO.OJ_SECOND.MORE') + this.$t('WARN.OJ_MESSAGE_TIME_AGO.OJ_AGO');
                }
            },
            getUrlKey: function (key) {
                return fun.getUrlKey(key);
            },
            addUrlParm: function (key, value) {
                if (fun.getUrlKey("result") != null) this.forms.statusForm.result = fun.getUrlKey("result");
                if (fun.getUrlKey("uinfo") != null) this.forms.statusForm.userInfo = fun.getUrlKey("uinfo");
                if (fun.getUrlKey("pid") != null) this.forms.statusForm.problemId = fun.getUrlKey("pid");
                if (fun.getUrlKey("lang") != null) this.forms.statusForm.lang = fun.getUrlKey("lang");
                if (fun.getUrlKey("page") != null) this.forms.statusForm.page = fun.getUrlKey("page");

                if ("result" == key) this.forms.statusForm.result = value != null ? value : null;
                if ("uinfo" == key) this.forms.statusForm.userInfo = value != null ? value : null;
                if ("pid" == key) this.forms.statusForm.problemId = value != null ? value : null;
                if ("lang" == key) this.forms.statusForm.lang = value != null ? value : null;
                if ("page" == key) this.forms.statusForm.page = value != null && value != "" ? value : null;
            },
            getUrlString: function () {
                var str = "";
                if (this.forms.statusForm.page != null) str += "&page=" + encodeURIComponent(this.forms.statusForm.page);
                if (this.forms.statusForm.result != null) str += "&result=" + encodeURIComponent(this.forms.statusForm.result);
                if (this.forms.statusForm.userInfo != null) str += "&uinfo=" + encodeURIComponent(this.forms.statusForm.userInfo);
                if (this.forms.statusForm.problemId != null) str += "&pid=" + encodeURIComponent(this.forms.statusForm.problemId);
                if (this.forms.statusForm.lang != null) str += "&lang=" + encodeURIComponent(this.forms.statusForm.lang);
                return str.replace("&", "?");
            },
            chooseUserInfo: function () {
                this.settings.status.search.userInfo = this.settings.status.search.userInfo == "" ? null : this.settings.status.search.userInfo;
                this.addUrlParm("uinfo", this.settings.status.search.userInfo);
                var url =  "/status.html" + this.getUrlString();
                window.location.href = url;
            },
            chooseProblemId: function () {
                this.settings.status.search.problemId = this.settings.status.search.problemId == "" ? null : this.settings.status.search.problemId;
                this.addUrlParm("pid", this.settings.status.search.problemId);
                var url =  "/status.html" + this.getUrlString();
                window.location.href = url;
            },
            switchResultType: function (n, t) {
                if (n == 1) this.settings.status.resultTypeList.a = t;
                else this.settings.status.resultTypeList.b = t;
            },
            switchResult: function (r) {
                this.addUrlParm("result", r);
                var url = "/status.html" + this.getUrlString();
                window.location.href = url;
            },
            switchLangType: function (n, t) {
                if (n == 1) this.settings.status.langTypeList.a = t;
                else this.settings.status.langTypeList.b = t;
            },
            switchLang: function (r) {
                this.addUrlParm("lang", r);
                var url =  "/status.html" + this.getUrlString();
                window.location.href = url;
            },
            transResultString: function (r) {
                if (r == null) return "";
                else {
                    var result = this.GLOBAL.OJ_MESSAGE_RESULT_STRING.get(r);
                    return this.$t("ANS." + result);
                }
            },
            transResultColor: function (r) {
                if (r == null) return "";
                else {
                    var result = this.GLOBAL.OJ_MESSAGE_RESULT_COLOR_CLASS.get(r);
                    return result;
                }
            },
            transLangString: function (r) {
                if (r == null) return "";
                else {
                    var result = this.GLOBAL.OJ_MESSAGE_LANG_STRING.get(r);
                    return this.$t("LANG." + result);
                }
            },
            async refresh(){
                var _this = this
                setTimeout(async function () {
                    // console.log(1)
                    let data = await fun.refresh();
                    if (data.OJ_ERROR_TYPE == _this.GLOBAL.OJ_ERROR_NO_ERROR) {
                        _this.settings.base.isLogin = true;
                        _this.settings.base.userInfo = data.OJ_USER_INFO;
                    }else{
                        window.location.href = '/loginpage.html';
                    }
                    _this.refresh()
                }, 1000*60*20)
            },
            identify: async function () {
                let data = await fun.idenfity();
                this.$i18n.locale = data.OJ_LANGUAGE_TYPE;
                if (data.OJ_ERROR_TYPE == this.GLOBAL.OJ_ERROR_NO_ERROR) {
                    this.settings.base.isLogin = true;
                    this.settings.base.userInfo = data.OJ_USER_INFO;
                }
                this.refresh()
                return data;
            },
            searchStatus() {
                var _this = this
                return window.axios.post(_this.GLOBAL.OJ_DEFAULT_BACK_SERVE + '/solution/list', fun.stringify(_this.forms.solutionForm), {
                    headers: {
                        OJ_ACCESS_TOKEN: fun.getCookie("AccessToken"),
                    }
                })
            },
        },
        async created() {
            await this.identify();
            this.settings.base.beforeLoad = false;

            this.forms.statusForm.result = fun.getUrlKey("result") == null ? null : Number(fun.getUrlKey("result"));
            this.forms.statusForm.lang = fun.getUrlKey("lang") == null ? null : Number(fun.getUrlKey("lang"));
